  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './list.scss';
 10→import { ListContext } from './list_context';
 11→
 12→interface ListProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  onActiveIndexChange?: (index: number) => void;
 16→  onAction?: (index: number) => void;
 17→  detail?: ReactNode;
 18→}
 19→
 20→export function List({
 21→  children,
 22→  itemCount,
 23→  onActiveIndexChange,
 24→  onAction,
 25→  detail,
 26→}: ListProps) {
 27→  const [activeIndex, setActiveIndexRaw] = useState(0);
 28→  const containerRef = useRef<HTMLDivElement>(null);
 29→
 30→  const setActiveIndex = useCallback(
 31→    (index: number) => {
 32→      setActiveIndexRaw(index);
 33→      onActiveIndexChange?.(index);
 34→    },
 35→    [onActiveIndexChange],
 36→  );
 37→
 38→  useEffect(() => {
 39→    if (itemCount === 0) {
 40→      setActiveIndex(0);
 41→    } else if (activeIndex >= itemCount) {
 42→      setActiveIndex(itemCount - 1);
 43→    }
 44→  }, [
 45→    itemCount,
 46→    activeIndex,
 47→    setActiveIndex,
 48→  ]);
 49→
 50→  useEffect(() => {
 51→    const container = containerRef.current;
 52→    if (!container) return;
 53→
 54→    const activeElement = container.querySelector<HTMLElement>(
 55→      `[data-list-index="${activeIndex}"]`,
 56→    );
 57→    activeElement?.scrollIntoView({ block: 'nearest' });
 58→  }, [activeIndex]);
 59→
 60→  useEffect(() => {
 61→    function handleKeyDown(e: KeyboardEvent) {
 62→      if (itemCount === 0) return;
 63→
 64→      if (e.ctrlKey && !e.metaKey && !e.altKey) {
 65→        if (e.key === 'n') {
 66→          e.preventDefault();
 67→          setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 68→          return;
 69→        }
 70→        if (e.key === 'p') {
 71→          e.preventDefault();
 72→          setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 73→          return;
 74→        }
 75→      }
 76→
 77→      if (e.metaKey || e.ctrlKey || e.altKey) return;
 78→
 79→      if (e.key === 'ArrowDown') {
 80→        e.preventDefault();
 81→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 82→      } else if (e.key === 'ArrowUp') {
 83→        e.preventDefault();
 84→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 85→      } else if (e.key === 'Enter') {
 86→        e.preventDefault();
 87→        onAction?.(activeIndex);
 88→      }
 89→    }
 90→
 91→    window.addEventListener('keydown', handleKeyDown);
 92→    return () => window.removeEventListener('keydown', handleKeyDown);
 93→  }, [
 94→    activeIndex,
 95→    itemCount,
 96→    setActiveIndex,
 97→    onAction,
 98→  ]);
 99→
100→  const contextValue = useMemo(
101→    () => ({
102→      activeIndex,
103→      setActiveIndex,
104→    }),
105→    [
106→      activeIndex,
107→      setActiveIndex,
108→    ],
109→  );
110→
111→  if (detail != null) {
112→    return (
113→      <ListContext value={contextValue}>
114→        <div className="list-detail-split">
115→          <div
116→            ref={containerRef}
117→            className="list list--with-detail"
118→            role="listbox"
119→            id="command-list"
120→          >
121→            {children}
122→          </div>
123→          <div
124→            className="list-detail-panel"
125→            role="complementary"
126→            aria-label="Item detail"
127→          >
128→            {detail}
129→          </div>
130→        </div>
131→      </ListContext>
132→    );
133→  }
134→
135→  return (
136→    <ListContext value={contextValue}>
137→      <div ref={containerRef} className="list" role="listbox" id="command-list">
138→        {children}
139→      </div>
140→    </ListContext>
141→  );
142→}
