  89→interface StoredQuicklink {
  90→  id: string;
  91→  name: string;
  92→  link: string;
  93→  type: QuicklinkType;
  94→  application?: string;
  95→  tags?: {
  96→    text: string;
  97→    color?: string;
  98→  }[];
  99→  createdAt: string;
 100→}
 101→
 102→function isStoredTag(value: unknown): value is {
 103→  text: string;
 104→  color?: string;
 105→} {
 106→  if (!isRecord(value)) return false;
 107→  if (typeof value.text !== 'string') return false;
 108→  if ('color' in value && typeof value.color !== 'string') {
 109→    return false;
 110→  }
 111→  return true;
 112→}
 113→
 114→function isQuicklinkType(value: string): value is QuicklinkType {
 115→  return value === 'url' || value === 'file' || value === 'deeplink';
 116→}
 117→
 118→function isStoredQuicklinkArray(value: unknown): value is StoredQuicklink[] {
 119→  if (!Array.isArray(value)) return false;
 120→  return value.every(
 121→    v =>
 122→      isRecord(v) &&
 123→      typeof v.id === 'string' &&
 124→      typeof v.name === 'string' &&
 125→      typeof v.link === 'string' &&
 126→      typeof v.type === 'string' &&
 127→      typeof v.createdAt === 'string' &&
 128→      (!v.application || typeof v.application === 'string') &&
 129→      (!v.tags || (Array.isArray(v.tags) && v.tags.every(isStoredTag))),
 130→  );
 131→}
 132→
 133→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
 134→
 135→function isTagColor(value: string): value is TagColor {
 136→  return TAG_COLOR_NAMES.has(value);
 137→}
 138→
 139→function serializeEntries(entries: QuicklinkEntry[]): StoredQuicklink[] {
 140→  return entries.map(e => ({
 141→    id: e.id,
 142→    name: e.name,
 143→    link: e.link,
 144→    type: e.type,
 145→    application: e.application,
 146→    tags: e.tags,
 147→    createdAt: e.createdAt.toISOString(),
 148→  }));
 149→}
 150→
 151→function deserializeEntries(stored: StoredQuicklink[]): QuicklinkEntry[] {
 152→  return stored.map(s => {
 153→    const parsed = new Date(s.createdAt);
 154→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
 155→    return {
 156→      id: s.id,
 157→      name: s.name,
 158→      link: s.link,
 159→      type: isQuicklinkType(s.type) ? s.type : 'url',
 160→      application: s.application,
 161→      icon: getQuicklinkIcon(isQuicklinkType(s.type) ? s.type : 'url'),
 162→      tags: s.tags?.map(t => ({
 163→        text: t.text,
 164→        color: t.color && isTagColor(t.color) ? t.color : undefined,
 165→      })),
 166→      createdAt,
 167→    };
 168→  });
 169→}
 170→
 171→function loadQuicklinks(): QuicklinkEntry[] {
 172→  const stored = storageGet(QUICKLINKS_KEY, isStoredQuicklinkArray);
 173→  if (stored) return deserializeEntries(stored);
 174→  return MOCK_QUICKLINKS;
 175→}
 176→
 177→function saveQuicklinks(entries: QuicklinkEntry[]) {
 178→  storageSet(QUICKLINKS_KEY, serializeEntries(entries));
 179→}
